#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int** createDP(int N, int M) {
    int** dp = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        dp[i] = (int*)malloc(M * sizeof(int));
    }
    return dp;
}

void freeDP(int** dp, int N) {
    for (int i = 0; i < N; i++) {
        free(dp[i]);
    }
    free(dp);
}

int solve(int N, int M, int K, int** edges) {
    int** dp = createDP(N, M);
    // Initialize DP array
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            dp[i][j] = 1;
        }
    }
    // Update DP array based on edges
    for (int i = 0; i < N - 1; i++) {
        int u = edges[i][0] - 1;
        int v = edges[i][1] - 1;
        for (int j = 0; j < M; j++) {
            for (int k = 0; k < M; k++) {
                if (abs(j - k) >= K) {
                    dp[v][k] = (dp[v][k] + dp[u][j]) % MOD;
                }
            }
        }
    }
    // Calculate total number of ways
    int total = 0;
    for (int i = 0; i < M; i++) {
        total = (total + dp[N - 1][i]) % MOD;
    }
    freeDP(dp, N);
    return total;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int** edges = (int**)malloc((N - 1) * sizeof(int*));
        for (int i = 0; i < N - 1; i++) {
            edges[i] = (int*)malloc(2 * sizeof(int));
            scanf("%d %d", &edges[i][0], &edges[i][1]);
        }
        int result = solve(N, M, K, edges);
        printf("%d\n", result);
        for (int i = 0; i < N - 1; i++) {
            free(edges[i]);
        }
        free(edges);
    }
    return 0;
}

