def solve(N, M, K, edges):
    MOD = 1000000007
    dp = [[1] * M for _ in range(N)]
    # Update DP array based on edges
    for u, v in edges:
        for j in range(M):
            for k in range(M):
                if abs(j - k) >= K:
                    dp[v - 1][k] = (dp[v - 1][k] + dp[u - 1][j]) % MOD
    # Calculate total number of ways
    total = sum(dp[-1]) % MOD
    return total

